#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include "../common.h"
#include "../util/timer/timer.h"

static void findK_parallel(long height,
                           knode *knodes,
                           long knodes_elem,
                           record *records,
                           long *currKnode,
                           long *offset,
                           int *keys,
                           record *ans,
                           int count,
                           int threads_per_block)
{
    #pragma omp parallel for num_threads(count)
    for (int bid = 0; bid < count; bid++) {
        long local_currKnode = currKnode[bid];
        long local_offset = offset[bid];
        int key_val = keys[bid];

        for (long i = 0; i < height; i++) {
            int found = 0;

            for (int thid = 0; thid < threads_per_block; thid++) {
                if (key_val >= knodes[local_currKnode].keys[thid] && 
                    knodes[local_currKnode].keys[thid+1] > key_val) {

                    if (knodes_elem > knodes[local_offset].indices[thid]) {
                        local_offset = knodes[local_offset].indices[thid];
                    }
                    found = 1;
                    break; 
                }
            }

            if (found) {
                local_currKnode = local_offset;
            }
        }

        for (int thid = 0; thid < threads_per_block; thid++) {
            if (knodes[local_currKnode].keys[thid] == key_val) {
                ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
                break;
            }
        }

        currKnode[bid] = local_currKnode;
        offset[bid] = local_offset;
    }
}

void 
kernel_gpu_cuda_wrapper(record *records,
                        long records_mem,
                        knode *knodes,
                        long knodes_elem,
                        long knodes_mem,
                        int order,
                        long maxheight,
                        int count,
                        long *currKnode,
                        long *offset,
                        int *keys,
                        record *ans)
{
    long long time0, time1, time2, time3, time4, time5, time6;
    int threadsPerBlock = 1024 > order ? order : 1024;

    time0 = get_time();
    time1 = get_time();
    time2 = get_time();
    time3 = get_time();

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", count, threadsPerBlock);

    time4 = get_time();

    findK_parallel(maxheight, knodes, knodes_elem, records, currKnode, offset, keys, ans, count, threadsPerBlock);

    time5 = get_time();
    time6 = get_time();

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n", (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n", (float)(time5-time4)/1000000, (float)(time5-time4)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", (float)(time6-time5)/1000000, (float)(time6-time5)/(float)(time6-time0)*100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time6-time0)/1000000);
}

void 
kernel_cpu(int cores_arg,
           record *records,
           knode *knodes,
           long knodes_elem,
           int order,
           long maxheight,
           int count,
           long *currKnode,
           long *offset,
           int *keys,
           record *ans)
{
    kernel_gpu_cuda_wrapper(records, 0, knodes, knodes_elem, 0, order, maxheight, count, currKnode, offset, keys, ans);
}

#ifdef __cplusplus
}
#endif

