static void findRangeK_parallel(long height,
                                knode *knodes,
                                long knodes_elem,
                                long *x_2,
                                long *v_3,
                                long *data_4,
                                long *offset_2D,
                                int *x_0,
                                int *var_7,
                                int *RecstartD,
                                int *elem_1,
                                int count,
                                int threads_per_block)
{
    #pragma omp parallel for num_threads(count)
    for (int elem_6 = 0; elem_6 < count; elem_6++) {
        long local_x_2 = x_2[elem_6];
        long local_data_4 = data_4[elem_6];
        long local_v_3 = v_3[elem_6];
        long local_offset_2D = offset_2D[elem_6];
        int x0_val = x_0[elem_6];
        int var7_val = var_7[elem_6];

        for (long i = 0; i < height; i++) {
            int found_start = 0;
            int found_end = 0;

            for (int data_5 = 0; data_5 < threads_per_block; data_5++) {
                if ((knodes[local_x_2].keys[data_5] <= x0_val) && 
                    (knodes[local_x_2].keys[data_5+1] > x0_val)) {
                    if (knodes_elem > knodes[local_x_2].indices[data_5]) {
                        local_v_3 = knodes[local_x_2].indices[data_5];
                    }
                    found_start = 1;
                }

                if ((var7_val >= knodes[local_data_4].keys[data_5]) && 
