                    if (knodes_elem > knodes[local_data_4].indices[data_5]) {
                        local_offset_2D = knodes[local_data_4].indices[data_5];
                    }
                    found_end = 1;
                }

                if (found_start && found_end) break;
            }

            if (found_start) local_x_2 = local_v_3;
            if (found_end) local_data_4 = local_offset_2D;
        }

        int recstart_val = -1;
        int length_val = 0;

        for (int data_5 = 0; data_5 < threads_per_block; data_5++) {
            if (x0_val == knodes[local_x_2].keys[data_5]) {
                recstart_val = knodes[local_x_2].indices[data_5];
            }
            if (var7_val == knodes[local_data_4].keys[data_5]) {
                length_val = knodes[local_data_4].indices[data_5] - recstart_val + 1;
            }
        }

        x_2[elem_6] = local_x_2;
        data_4[elem_6] = local_data_4;
        v_3[elem_6] = local_v_3;
        offset_2D[elem_6] = local_offset_2D;

        if (recstart_val != -1) RecstartD[elem_6] = recstart_val;
        if (length_val != 0) elem_1[elem_6] = length_val;
    }
}

